const logData = $input.first().json.data || 'No activity log data available.';
const today = new Date();
const apr15 = new Date('2026-04-15');
const daysLeft = Math.ceil((apr15 - today) / 86400000);
const dateStr = today.toLocaleDateString('en-US', {month: 'long', day: 'numeric', year: 'numeric'});
const prompt = `You are the CPAverse Tax Prep Agent for Josh Mauer CPA LLC. Generate a morning report email.

Today's date: ${dateStr}
Days until April 15, 2026: ${daysLeft}

Activity Log Contents:
${logData}

Format the report with sections: SUBJECT, COMPLETED SINCE LAST REPORT, NEEDS YOUR ATTENTION - URGENT, WAITING ON CLIENTS, DEADLINE WATCH, AGENT ACTIVITY SUMMARY. Return ONLY the formatted report.`;
return [{ json: { requestBody: { model: 'claude-sonnet-4-6', max_tokens: 2048, messages: [{ role: 'user', content: prompt }] } } }];

const response = $input.first().json;
const reportText = response.content[0].text;
const lines = reportText.split('\n');
let subject = 'CPAverse Agent Report';
let body = reportText;
for (const line of lines) {
  if (line.startsWith('SUBJECT:')) {
    subject = line.replace('SUBJECT:', '').trim();
    body = reportText.substring(reportText.indexOf('\n', reportText.indexOf('SUBJECT:')) + 1);
    break;
  }
}
const htmlBody = `<html><body><pre style="font-family: 'Courier New', monospace; font-size: 14px; line-height: 1.5; color: #1a365d;">${body}</pre></body></html>`;
return [{ json: { subject, body: htmlBody, plainBody: body } }];
